// Kill switch check + request prep for rotation health monitor
// Env vars required:
//   N8N_WORKFLOW_ROTATION_MONITOR_ENABLED: 'true' | 'false'

const enabled = $env.N8N_WORKFLOW_ROTATION_MONITOR_ENABLED;
if (enabled === 'false' || enabled === '0') {
  return [{ json: { killed: 'true', reason: 'kill_switch_disabled' } }];
}

const requestId = 'ops-rotation-monitor-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
const correlationId = 'n8n-rotation-monitor-' + new Date().toISOString().slice(0, 10);
const crypto = require('crypto');
const payloadHash = crypto.createHash('sha256').update(JSON.stringify({
  action: 'ops.rotation_health_check',
  date: new Date().toISOString().slice(0, 10)
})).digest('hex');
const idempotencyKey = crypto.createHash('sha256').update(
  requestId + 'ops.rotation_health_check' + payloadHash
).digest('hex');

return [{ json: {
  killed: 'false',
  requestId,
  correlationId,
  idempotencyKey,
  timestamp: new Date().toISOString()
} }];

const gatewayResult = $('GET Gateway Health').first().json || {};
const rawItems = $input.all().map((item) => item.json || {});
const rows = Array.isArray(rawItems[0]) ? rawItems[0] : rawItems;
const windowStart = Date.now() - (36 * 60 * 60 * 1000);
const gatewayError = gatewayResult.error || gatewayResult.message || gatewayResult.reason || gatewayResult.code;
const gatewayHealthy = !gatewayError && (gatewayResult.status === 'ok' || gatewayResult.healthy === true);
const queryError = (rows.length === 1 && rows[0] && typeof rows[0] === 'object')
  ? (rows[0].error || rows[0].message || rows[0].description || rows[0].reason || rows[0].code || rows[0].reason_code || null)
  : null;
const queryFailed = Boolean(queryError) || Boolean(rows[0] && rows[0].statusCode && Number(rows[0].statusCode) >= 400);
const receiptRows = queryFailed ? [] : rows.filter((row) => {
  if (!row || typeof row !== 'object' || Array.isArray(row) || !row.receipt_id) {
    return false;
  }
  const createdAt = Date.parse(row.created_at || '');
  return Number.isFinite(createdAt) && createdAt >= windowStart;
});
const actionTypeOf = (row) => row?.action?.action_type || row?.action?.actionType || null;
const failureRows = receiptRows.filter((row) => String(row.status || '').toUpperCase() === 'FAILED');
const batchCompleteRows = receiptRows.filter((row) => actionTypeOf(row) === 'ops.secret_rotation_batch_complete' && String(row.status || '').toUpperCase() === 'SUCCEEDED');
const triggerSuccessRows = receiptRows.filter((row) => actionTypeOf(row) === 'ops.trigger_rotation' && String(row.status || '').toUpperCase() === 'SUCCEEDED');
const noRecentActivity = !queryFailed && receiptRows.length === 0;
const missingBatchCompletion = !queryFailed && receiptRows.length > 0 && batchCompleteRows.length === 0;
const failureReasons = [];
if (noRecentActivity) {
  failureReasons.push('no_recent_rotation_receipts');
}
if (missingBatchCompletion) {
  failureReasons.push('missing_batch_completion');
}
for (const row of failureRows.slice(0, 10)) {
  failureReasons.push(actionTypeOf(row) || row.receipt_id);
}
const hasRotationFailures = failureReasons.length > 0;
const allHealthy = gatewayHealthy && !queryFailed && !hasRotationFailures;
return [{ json: {
  all_healthy: allHealthy,
  gateway_healthy: gatewayHealthy,
  has_rotation_failures: hasRotationFailures,
  rotation_failures: failureReasons,
  rotation_failure_count: failureReasons.length,
  query_failed: queryFailed,
  query_error: queryFailed ? queryError : null,
  checked_at: new Date().toISOString(),
  recent_batch_success_count: batchCompleteRows.length,
  recent_rotation_success_count: triggerSuccessRows.length,
  recent_failure_receipts: failureRows.slice(0, 10).map((row) => ({ receipt_id: row.receipt_id, action_type: actionTypeOf(row), created_at: row.created_at, status: row.status }))
} }];

const crypto = require('crypto');
const prep = $('Kill Switch + Prep').first().json;
const payload = {
  id: prep.requestId,
  env: $env.ASPIRE_ROBOT_ENV || 'production',
  suite: $env.ASPIRE_ROBOT_SUITE || 'aspire_robots',
  status: 'passed',
  startedAt: prep.timestamp || new Date().toISOString(),
  finishedAt: new Date().toISOString(),
  versionRef: ($env.ASPIRE_ROBOT_VERSION_REF || 'n8n-live') + ':rotation-monitor',
  summary: 'Rotation health monitor is healthy',
  scenarios: [{
    name: 'rotation_health',
    status: 'passed',
    summary: 'Rotation health monitor is healthy',
    evidence: [
      `correlation:${prep.correlationId}`,
      `gateway_healthy:${$json.gateway_healthy}`,
      `rotation_failures:${$json.rotation_failure_count || 0}`
    ]
  }],
  meta: { workflow: 'rotation-monitor', correlationId: prep.correlationId, requestId: prep.requestId, gatewayHealthy: $json.gateway_healthy, rotationFailureCount: $json.rotation_failure_count || 0 }
};
const robotBody = JSON.stringify(payload);
const robotSignature = crypto.createHmac('sha256', $env.ASPIRE_ROBOT_S2S_SECRET).update(robotBody).digest('hex');
return [{ json: { ...$json, robotBody, robotSignature } }];

